INSERT INTO entries (student_id, assignment_id, date_submitted, writing_sample, student_feedback, teacher_notes, word_count, flagged_for_followup) VALUES
  (1, 1, '2025-09-15', 'The peppered moth shows natural selection. Light moths hid on clean bark while dark moths blended with soot. Over time the population shifted.', 'Glow: Clear cause and effect. Grow: Name your graph source explicitly.', 'Model sentence stems next time.', 23, false),
  (1, 2, '2025-10-08', 'If wolves leave Yellowstone elk eat more plants. Streams change because plants hold soil. This is a cascade through the food web.', 'Glow: Connected species to habitat. Grow: Add one numeric detail from the reading.', NULL, 22, false),
  (2, 1, '2025-09-16', 'Pollution made trees darker so dark moths survived better. That is adaptation to the environment in Britain during the Industrial Revolution.', 'Glow: Strong context. Grow: Use the word selective pressure.', 'Check understanding of adaptation vs acclimation.', 21, true),
  (2, 2, '2025-10-09', 'Removing sea otters lets urchins explode and kelp forests shrink. The ecosystem loses structure and fish lose nursery habitat.', 'Glow: Two-step reasoning. Grow: Cite the kelp article title.', NULL, 19, false),
  (3, 1, '2025-09-15', 'Natural selection means heritable traits that help survival become common. Moth color matched tree color so birds ate fewer camouflaged moths.', 'Glow: Defines selection well. Grow: Tie back to frequency change.', NULL, 21, false),
  (3, 2, '2025-10-07', 'Apex predators control herbivores. Without them plants get overgrazed and biodiversity drops in the grassland example.', 'Glow: Clear claim. Grow: Add evidence from the food web diagram.', 'Encourage labeling trophic levels.', 16, false),
  (4, 1, '2025-09-17', 'The textbook graph shows dark moth increase after 1850. The environment selected for camouflage on polluted trees.', 'Glow: Used the graph. Grow: Explain mechanism in one more sentence.', NULL, 17, false),
  (4, 2, '2025-10-10', 'Keystone species have outsized effects. Starfish removal from tide pools changed which species dominated the rocky shore.', 'Glow: Good example choice. Grow: Name the Pisaster study.', NULL, 17, true),
  (5, 1, '2025-09-16', 'Birds are the selective agent. They ate visible moths. Surviving moths reproduced and passed color genes to offspring.', 'Glow: Mentions reproduction. Grow: Link to allele frequency.', 'Review genetics vocabulary.', 18, false),
  (5, 2, '2025-10-08', 'Trophic cascade moves energy and matter through levels. Losing a producer hits every consumer above it eventually.', 'Glow: Big picture. Grow: Give one concrete species chain.', NULL, 17, false),
  (6, 1, '2025-09-18', 'Industrial melanism is the pattern. Dark phenotype rose where soot darkened bark then fell when air cleaned up.', 'Glow: Historical arc. Grow: Cite the recovery data table.', NULL, 18, false),
  (6, 2, '2025-10-11', 'Invasive species can remove natives and simplify food webs. That makes the system less stable during drought or disease.', 'Glow: Risk thinking. Grow: Add local Georgia example if possible.', NULL, 19, false),
  (7, 1, '2025-09-15', 'The moth story supports Darwin because variation existed and the environment changed which variant survived and reproduced most.', 'Glow: Links to Darwin. Grow: Define fitness in your own words.', NULL, 18, false),
  (7, 2, '2025-10-09', 'Primary producers capture energy. If they crash every higher level loses energy input and population sizes fall.', 'Glow: Energy angle. Grow: Mention photosynthesis once.', NULL, 17, false),
  (8, 1, '2025-09-17', 'Dark moths had higher survival in polluted forests because predators could not see them as easily on dark backgrounds.', 'Glow: Mechanism clear. Grow: Add a counterexample from clean forests.', 'Pair with sentence frame.', 19, true),
  (8, 2, '2025-10-10', 'Herbivore overpopulation strips vegetation then soil erodes. Rivers carry sediment and water quality declines downstream.', 'Glow: Cause chain. Grow: Cite the river turbidity source.', NULL, 15, false),
  (9, 1, '2025-09-16', 'Frequency of alleles changed when selection favored dark coloring. That is evolution in a population not just individual change.', 'Glow: Allele language. Grow: Shorten long sentences.', NULL, 19, false),
  (9, 2, '2025-10-08', 'Detritivores recycle nutrients. If they decline nutrients lock in dead material and plant growth slows.', 'Glow: Nutrient cycling. Grow: Connect to decomposers lesson.', NULL, 15, false),
  (10, 1, '2025-09-18', 'Peppered moths are a classic example because data spans decades and matches prediction from natural selection theory.', 'Glow: Meta-level insight. Grow: Add one data point from the graph.', NULL, 17, false),
  (10, 2, '2025-10-11', 'Removing sharks can increase ray populations which then reduce shellfish. Fisheries and habitats both change.', 'Glow: Human relevance. Grow: Label claim vs evidence.', NULL, 15, false),
  (11, 1, '2025-09-15', 'Selection acts on phenotypes. Moth color is phenotype tied to genotype and the environment determines which phenotype hides best.', 'Glow: Phenotype link. Grow: Simplify jargon for clarity.', NULL, 19, false),
  (11, 2, '2025-10-07', 'Biodiversity buffers ecosystems. More species mean more pathways for energy flow if one pathway is disrupted.', 'Glow: Stability idea. Grow: Use one vocabulary term from the rubric.', NULL, 16, false),
  (12, 1, '2025-09-17', 'The moth case shows rapid change when selection is strong. Clean air reversed selection pressure toward lighter moths again.', 'Glow: Reversible change noted. Grow: Quantify with percentages if available.', NULL, 19, false),
  (12, 2, '2025-10-10', 'Food web models predict indirect effects. A small change at one node can ripple widely especially with few redundant links.', 'Glow: Network thinking. Grow: Name two nodes from class model.', NULL, 20, false),
  (13, 1, '2025-09-16', 'Evidence includes museum records and field surveys showing moth color ratios shifting with pollution levels over time.', 'Glow: Evidence types. Grow: Explain why surveys matter.', NULL, 17, false),
  (13, 2, '2025-10-09', 'Competitive release happens when a dominant competitor disappears. Remaining species expand into open niche space quickly.', 'Glow: Niche vocabulary. Grow: Tie to trophic cascade definition.', NULL, 16, false),
  (14, 1, '2025-09-18', 'Camouflage is an adaptation shaped by predation. Moths that matched bark avoided bird attacks and lived to reproduce.', 'Glow: Adaptation defined. Grow: Add source citation.', NULL, 18, false),
  (14, 2, '2026-03-18', 'Ecosystem engineers like beavers reshape habitats. Removing them changes water flow and therefore plant and fish communities.', 'Glow: Engineer concept. Grow: One more concrete beaver behavior.', NULL, 17, true),
  (15, 1, '2025-09-15', 'Students should connect genotype to phenotype to selection. The moth allele frequencies track environmental change.', 'Glow: Genotype mention. Grow: Stay in student voice; avoid meta commentary.', 'Discuss audience — rewrite as first person.', 15, true),
  (15, 2, '2026-03-19', 'Trophic cascades connect predators to producers indirectly. Even small shifts can reorganize community structure when links are tight.', 'Glow: Strong synthesis. Grow: Cite one class source by name.', NULL, 18, false);
